+char* JfrRedactedEvents::new_redacted_text() {
+  char* result = NEW_C_HEAP_ARRAY(char, REDACTED_LENGTH + 1, mtTracing);
+  strncpy(result, REDACTED, REDACTED_LENGTH + 1);
+  return result;
+}
